                    zones['Zone 1'] += 1
                elif hr < 140:
                    zones['Zone 2'] += 1
                elif hr < 160:
                    zones['Zone 3'] += 1
                elif hr < 180:
                    zones['Zone 4'] += 1
                else:
                    zones['Zone 5'] += 1
            self.intensity_zones[sport] = zones

    def display_dashboard(self, sport=None):
        if sport is None:
            sport_data = self.data
        else:
