from datetime import datetime, timedelta
import matplotlib.pyplot as plt

class FitnessTracker:
    def __init__(self, api_keys):
        self.api_keys = api_keys
        self.data = {}

    def fetch_data(self):
        for app, key in self.api_keys.items():
            if app == 'strava':
                self.fetch_strava_data(key)
            elif app == 'polar':
                self.fetch_polar_data(key)
            elif app == 'myfitnesspal':
                self.fetch_myfitnesspal_data(key)

    def fetch_strava_data(self, api_key):
        # Fetch Strava data using the API key
        url = f'https://www.strava.com/api/v3/athlete/activities'
        headers = {'Authorization': f'Bearer {api_key}'}
        response = requests.get(url, headers=headers)
        activities = json.loads(response.text)
        self.data['strava'] = activities

    def fetch_polar_data(self, api_key):
        # Fetch Polar data using the API key
        url = f'https://www.polaraccesslink.com/v3/activities'
        headers = {'Authorization': f'Bearer {api_key}'}
        response = requests.get(url, headers=headers)
        activities = json.loads(response.text)
        self.data['polar'] = activities

    def fetch_myfitnesspal_data(self, api_key):
        # Fetch MyFitnessPal data using the API key
        url = f'https://api.myfitnesspal.com/v2/diary'
        headers = {'Authorization': f'Bearer {api_key}'}
        response = requests.get(url, headers=headers)
        diary = json.loads(response.text)
        self.data['myfitnesspal'] = diary

    def generate_dashboard(self):
        # Create a dashboard with the fetched data
        fig, ax = plt.subplots(figsize=(12, 6))

        # Plot exercise data
        for app, activities in self.data.items():
            if app == 'strava':
                for activity in activities:
                    ax.plot(activity['start_date'], activity['total_distance'], label=f'{app} - {activity["name"]}')
            elif app == 'polar':
                for activity in activities:
                    ax.plot(activity['start_time'], activity['duration'], label=f'{app} - {activity["name"]}')
            elif app == 'myfitnesspal':
                for entry in activities['entries']:
                    ax.plot(entry['date'], entry['calories'], label=f'{app} - {entry["name"]}')

        ax.set_xlabel('Date')
        ax.set_ylabel('Activity')
        ax.set_title('Fitness Dashboard')
        ax.legend()
        plt.show()

    def customize_dashboard(self, metric, time_range):
        # Customize the dashboard based on the selected metric and time range
        fig, ax = plt.subplots(figsize=(12, 6))

        if metric == 'distance':
            for app, activities in self.data.items():
                if app == 'strava':
                    for activity in activities:
                        if time_range[0] <= datetime.strptime(activity['start_date'], '%Y-%m-%dT%H:%M:%SZ') <= time_range[1]:
                            ax.plot(activity['start_date'], activity['total_distance'], label=f'{app} - {activity["name"]}')
                elif app == 'polar':
                    for activity in activities:
                        if time_range[0] <= datetime.strptime(activity['start_time'], '%Y-%m-%dT%H:%M:%SZ') <= time_range[1]:
                            ax.plot(activity['start_time'], activity['distance'], label=f'{app} - {activity["name"]}')
        elif metric == 'duration':
            for app, activities in self.data.items():
                if app == 'strava':
                    for activity in activities:
                        if time_range[0] <= datetime.strptime(activity['start_date'], '%Y-%m-%dT%H:%M:%SZ') <= time_range[1]:
                            ax.plot(activity['start_date'], activity['moving_time'], label=f'{app} - {activity["name"]}')
                elif app == 'polar':
                    for activity in activities:
                        if time_range[0] <= datetime.strptime(activity['start_time'], '%Y-%m-%dT%H:%M:%SZ') <= time_range[1]:
                            ax.plot(activity['start_time'], activity['duration'], label=f'{app} - {activity["name"]}')
        elif metric == 'calories':
            for app, activities in self.data.items():
                if app == 'myfitnesspal':
                    for entry in activities['entries']:
                        if time_range[0] <= datetime.strptime(entry['date'], '%Y-%m-%d') <= time_range[1]:
                            ax.plot(entry['date'], entry['calories'], label=f'{app} - {entry["name"]}')

        ax.set_xlabel('Date')
        ax.set_ylabel(metric.capitalize())
        ax.set_title(f'Fitness Dashboard - {metric.capitalize()}')
